import{_ as a,r as t,o as c,c as d,a as o,b as e,d as i,e as n}from"./app-25fa875f.js";const l="/blog/assets/traceroute-windows-30f6bf87.png",s="/blog/assets/traceroute-icmp-26720dd0.png",p="/blog/assets/traceroute-udp-ec73c96a.png",h={},u=n('<h1 id="network-traceroute" tabindex="-1"><a class="header-anchor" href="#network-traceroute" aria-hidden="true">#</a> Network - Traceroute</h1><p>Created by : Mr Dk.</p><p>2018 / 12 / 26 11:24</p><p>Nanjing, Jiangsu, China</p><hr><h2 id="about" tabindex="-1"><a class="header-anchor" href="#about" aria-hidden="true">#</a> About</h2><p><em>Traceroute</em> 是用来检测从 <strong>发出数据包的主机</strong> 到 <strong>目标主机</strong> 之间所经过的网关数量的工具。在 <em>Windows</em> 下叫做 <em>tracert</em>，可以定位从发送主机到目标主机之间的所有路由器。主要原理：操纵数据包中的 <code>TTL</code> 字段进行步步试探。</p><p><img src="'+l+'" alt="traceroute-windows"></p><p><em>Windows</em> 下的 <em>tracert</em>：</p><ul><li>当前主机 IP 地址为 <code>[153.3.101.244]</code>，尝试对 <em>Baidu</em> 进行 traceroute</li><li>默认参数最大 TTL 为 30</li><li>默认参数对每个 TTL 发出 3 个探测包</li></ul><h2 id="ttl" tabindex="-1"><a class="header-anchor" href="#ttl" aria-hidden="true">#</a> TTL</h2><p><em>TTL (Time-To-Live)</em> 是 IP 数据包中的一个字段，指定了数据包最多能经过几次路由器：</p><ul><li>IP 数据包每经过一次路由器，<code>TTL</code> 的值就会被减掉 <code>1</code></li><li><code>TTL</code> 被减至 <code>0</code> 时，该数据包将被路由器丢弃，不再继续转发，同时路由器向源地址发送一个超时报文</li></ul><h2 id="theory" tabindex="-1"><a class="header-anchor" href="#theory" aria-hidden="true">#</a> Theory</h2><p><em>Traceroute</em> 的原理是，向目的地址发送 <code>TTL</code> 从 <code>1</code> 开始逐渐增大的数据包：</p><ul><li><code>TTL == 1</code> 时，第一跳路由器将会返回超时报文</li><li><code>TTL == 2</code> 时，第二跳路由器将会返回超时报文</li><li>......</li><li>直到 <code>TTL</code> 的值能够到达目的地址，目的地址返回一个确认信号（可能是不同形式的）</li><li>或者到达最大 <code>TTL</code> 限制，也没有到达目的地址</li></ul><h2 id="implementation-based-on-icmp" tabindex="-1"><a class="header-anchor" href="#implementation-based-on-icmp" aria-hidden="true">#</a> Implementation Based on ICMP</h2><p>发送 ICMP echo request，实际上就是 <em>ping</em> 命令。如果 TTL 超时，将会返回 <code>ICMP-TTL-Exceeded</code> 报文；如果到达目的地址，将会返回 <code>ICMP echo reply</code> 报文，暗示 traceroute 结束。</p><p><img src="'+s+'" alt="traceroute-icmp"></p><p>可能出现的问题：</p><ul><li>有些服务器或防火墙会因为安全原因不回复 <code>ICMP echo reply</code></li><li>有些路由器会 <strong>安静</strong> 地丢掉 TTL 减小到 0 的数据包，即不返回 TTL 超时报文</li></ul><h2 id="implementation-based-on-udp" tabindex="-1"><a class="header-anchor" href="#implementation-based-on-udp" aria-hidden="true">#</a> Implementation Based on UDP</h2><p>发送 UDP 数据包，使用一个大于 <code>30000</code> 的端口号。如果 TTL 超时，将返回 <code>ICMP-TTL-Exceeded</code>；如果到达目的地址，由于服务器通常不会使用大于 <code>30000</code> 的端口号，将返回 <code>ICMP-port-unreachable</code>，暗示 traceroute 结束。</p><p><img src="'+p+'" alt="traceroute-udp"></p><p>可能出现的问题：</p><ul><li>UDP 由于经常被用来做网络攻击 (无需连接，没有状态约束)，因此 ISP 出于安全考虑会采用端口白名单，只有在白名单端口中的数据包才能通过</li><li>服务器可能出于安全原因不提供 UDP 服务</li><li>可能被防火墙过滤</li></ul><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references" aria-hidden="true">#</a> References</h2>',27),m={href:"https://www.jianshu.com/p/75a5822d0eec",target:"_blank",rel:"noopener noreferrer"},T=o("hr",null,null,-1);function _(b,f){const r=t("ExternalLinkIcon");return c(),d("div",null,[u,o("p",null,[e("图片来自 "),o("a",m,[e("简书"),i(r)]),e("。")]),T])}const g=a(h,[["render",_],["__file","Network Traceroute.html.vue"]]);export{g as default};
